#!/usr/bin/env node

/**
 * Generate GitHub-friendly Markdown report from eval results
 *
 * Usage: node generate-eval-report.js <skill-path>
 * Example: node generate-eval-report.js cloud-service/dispatcher/config-authoring
 */

const fs = require('fs');
const path = require('path');

const skillPath = process.argv[2];
if (!skillPath) {
  console.error('Error: skill path required');
  console.error('Usage: node generate-eval-report.js <skill-path>');
  process.exit(1);
}

const resultsPath = path.join(
  'evals-workspace',
  skillPath,
  'iteration-1',
  'results.json'
);

if (!fs.existsSync(resultsPath)) {
  console.error(`Error: Results not found at ${resultsPath}`);
  process.exit(1);
}

const results = JSON.parse(fs.readFileSync(resultsPath, 'utf8'));

let report = `## 🧪 Skill Evaluation Report

**Skill:** ${results.skill}
**Variant:** ${results.variant}
**Iteration:** ${results.iteration}
**Timestamp:** ${new Date(results.timestamp).toLocaleString()}

### Summary

| Metric | Value |
|--------|-------|
| **Total** | ${results.summary.total} |
| **✅ Passed** | ${results.summary.passed} |
| **❌ Failed** | ${results.summary.failed} |
| **Pass Rate** | ${(results.summary.passed / results.summary.total * 100).toFixed(1)}% |

`;

// Add test case details
report += `### Test Cases\n\n`;

for (const tc of results.test_cases) {
  const icon = tc.status === 'passed' ? '✅' : '❌';
  const statusBadge = tc.status === 'passed'
    ? '![PASS](https://img.shields.io/badge/status-PASS-success)'
    : '![FAIL](https://img.shields.io/badge/status-FAIL-critical)';

  report += `<details>\n`;
  report += `<summary><strong>${icon} ${tc.name}</strong> ${statusBadge}</summary>\n\n`;

  if (tc.assertions) {
    report += `**Assertions:** ${tc.assertions.passed}/${tc.assertions.total} passed\n\n`;

    for (const assertion of tc.assertions.results) {
      const aIcon = assertion.passed ? '✅' : '❌';
      report += `- ${aIcon} ${assertion.assertion}\n`;
      if (!assertion.passed && assertion.evidence) {
        report += `  > ${assertion.evidence}\n`;
      }
    }
    report += '\n';
  }

  if (tc.error) {
    report += `**Error:** \`${tc.error}\`\n\n`;
  }

  report += `</details>\n\n`;
}

// Add guidance
if (results.summary.failed > 0) {
  report += `### 🔧 Next Steps

The eval found ${results.summary.failed} failing test case(s). Consider:

1. **Review failing assertions** - Check if the skill output matches expected patterns
2. **Update skill references** - Add missing patterns or examples to \`SKILL.md\` or \`references/\`
3. **Refine assertions** - Ensure assertions are specific and verifiable
4. **Run locally** - Test changes with: \`cd evals/runner && npm run eval -- --skill ${skillPath}\`

`;
}

report += `---
*Generated by Adobe Skills Eval Runner*
`;

fs.writeFileSync('eval-report.md', report);
console.log('Report generated: eval-report.md');
